
import { Outlet, useLocation } from "react-router-dom";
import Header from "../../components/Header";
import Footer from '../../components/Footer'

function ServiceLayout() {
    const location = useLocation();
    const pageName = location.state?.pageName;
    const parent = location.state?.parent || "Home";
    const imageSrc = location.state?.imageSrc || null


    return (
        <>
            <div className='wrapper'>
                <Header />
                <div className="container-fluid cls-srvlay-main" style={{ backgroundImage: imageSrc ? `url('${process.env.PUBLIC_URL}/images/${imageSrc}')` : 'none', backgroundPosition: "center", backgroundSize: "cover" }}>
                    <div className="container cls-srvlay-content">
                        <h4 className="cls-shdow-text">{pageName}</h4>

                        <div className="row">
                            <p className="cls-shdow-text">{parent} / {pageName}</p>
                        </div>
                    </div>
                </div>
                <Outlet />
                <Footer />
            </div>
        </>
    );
}

export default ServiceLayout;